class Solution:
    def calories(self, calories: List[int], k: int, lower: int, upper: int) -> int:
        points = 0
        total = 0
        for i in range(len(calories)):
            total += calories[i]
            if total > k:
                total -= calories[i - k]
                if total < lower:
                    points -= 1
                elif total > upper:
                    points += 1
        return points

