class Solution:
    def totalHammingDistance(self, nums: List[int]) -> int:
        d = defaultdict(int)
        for x in nums:
            for i in range(32):
                d[x >> i] += x
        return sum(d[a] ^ d[b] for a, b in combinations(nums, 2))

