class Solution:
    def wordBreak(self, s: str, wordDict: List[str]) -> bool:
        n = len(s)
        m = len(wordDict)
        dp = [[False] * (n + 1) for _ in range(m)]
        for i in range(m):
            for j in range(n):
                if j + len(wordDict[i]) > n:
                    break
                dp[i][j + len(wordDict[i])] = dp[i][j] and s[j : j + len(wordDict[i])] == wordDict[i]
        for j in range(n, -1, -1):
            for i in range(m):
                if dp[i][j] and j + len(wordDict[i]) <= n:
                    dp[i][j + len(wordDict[i])] = True
        return dp[0][n]

