class Solution:
    def isOneEditDistance(self, s: str, t: str) -> bool:
        i, j = 0, 0
        while i < len(s) and j < len(t):
            if s[i] == t[j]:
                i, j = i + 1, j + 1
            else:
                if len(s) == len(t):
                    s[i] = t[j]
                elif s[i] == t[j]:
                    t = t[:j] + t[j + 1 :]
                else:
                    s = s[:i] + s[i + 1 :]
                i, j = i + 1, j + 1
        return i < len(s) and j < len(t)

