    def openLock(self, deadends: List[str], target: str) -> int:
        def dfs(x, y, z, w):
            if x in vis:
                return
            if x == target:
                d[x] = d[x] + 1
                return
            for i in range(10):
                for j in range(10):
                    for k in range(10):
