class Solution:
    def romanToInt(self, s: str) -> int:
        ans = 0
        prev = 0
        for i, c in enumerate(s, 1):
            if c == 'V':
                ans -= prev
            elif c == 'X':
                ans -= prev * 2
            elif c == 'I':
                ans -= prev
            else:
                ans += c
            prev = c
        return ans

