    def numIslands(self, grid: List[List[str]]) -> int:
        def dfs(i, j):
            if i < 0 or j < 0 or i >= n or j >= m or vis[i][j]:
                return
            vis[i][j] = 1
            for x, y in [(i - 1, j), (i + 1, j), (i, j - 1), (i, j + 1)]:
                dfs(x, y)

        n, m = len(grid), len(grid[0])
        vis = [[0] * m for _ in range(n)]
        ans = 0
        for i in range(n):
            for j in range(m):
                if grid[i][j] == '1' and not vis[i][j]:
                    vis[i][j] = 1
                    ans += 1
                    dfs(i, j)
        return ans

